import pandas as pdfrom cache_manager import MarketDataCachedef test_cache_stores_and_returns_data():    cache = MarketDataCache()    df = pd.DataFrame({"Close": [100, 110, 120]})    cache.set_data("1 Week", df)    assert cache.get_data("1 Week").equals(df)def test_cache_returns_none_for_missing_data():    cache = MarketDataCache()    assert cache.get_data("1 Month") is Nonedef test_cache_removes_data():    cache = MarketDataCache()    df = pd.DataFrame({"Close": [100, 110, 120]})    cache.set_data("1 Week", df)    cache.remove_data("1 Week")    assert cache.get_data("1 Week") is Nonedef test_cache_stores_and_returns_graph():    cache = MarketDataCache()    fake_graph = object()    cache.set_graph("1 Week", False, fake_graph)    assert cache.get_graph("1 Week", False) is fake_graphdef test_cache_clear_graphs():    cache = MarketDataCache()    fake_graph = object()    cache.set_graph("1 Week", False, fake_graph)    cache.clear_graphs()    assert cache.get_graph("1 Week", False) is None